#!/usr/bin/env dotnet
#:property PublishAot=false

// Find the earliest Friday the 13th in the proleptic Gregorian calendar (from 0001-01-01)
// and count total Friday the 13ths in a full 400-year cycle.

// Earliest Friday the 13th
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
DateTime? earliest = null;

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            earliest ??= d;
        }
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// Count in a full 400-year cycle (years 1–400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        if (new DateTime(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// Bonus: distribution by month
var byMonth = new int[12];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        if (new DateTime(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            byMonth[month - 1]++;
    }
}

Console.WriteLine("\nDistribution by month:");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateTime(1, m + 1, 1):MMMM,-10} {byMonth[m]}");

